        }
    },
    {
        "inputs": {"incoming_damage": 10, "planned_block": 12, "current_hp": 30},
        "expected_contains": "SAFE"
    }
]

SCHEMA = {
    "name": "poison_lethal_turns",
    "description": "Calculates how many turns it will take for current poison to kill enemies, assuming no other damage. Helps decide if you can stop attacking and focus entirely on blocking.",
    "input_schema": {
        "type": "object",
        "properties": {
            "poison_stacks": {"type": ["integer", "array"]},
            "enemy_hp": {"type": ["integer", "array"]}
        },
        "required": ["poison_stacks", "enemy_hp"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(poison_stacks, enemy_hp):
    p_list = poison_stacks if isinstance(poison_stacks, list) else [poison_stacks]
    hp_list = enemy_hp if isinstance(enemy_hp, list) else [enemy_hp]

    results = []
    for p, hp in zip(p_list, hp_list):
        if p is None or hp is None:
            results.append({"turns_to_lethal": -1, "will_die": False, "damage_shortfall": hp if hp else 0})
            continue

        current_p = p
        current_hp = hp
        turns = 0
        while current_p > 0 and current_hp > 0:
            current_hp -= current_p
            current_p -= 1
            turns += 1

        results.append({
            "turns_to_lethal": turns if current_hp <= 0 else -1,
            "will_die": current_hp <= 0,
            "damage_shortfall": max(0, current_hp)
        })

    if not isinstance(poison_stacks, list) and not isinstance(enemy_hp, list):
        return results[0]
    return {"enemy_results": results}

TEST_CASES = [
    {
        "inputs": {"poison_stacks": 5, "enemy_hp": 12},
        "expected": {"turns_to_lethal": 3, "will_die": True, "damage_shortfall": 0}
    },
    {
        "inputs": {"poison_stacks": [4, 2], "enemy_hp": [10, 5]},
        "expected_contains": "enemy_results"
    }
]
